function Flag({i,s}){
  const f=FLAGS[ALL[i].s]||{t:"H",c:["#888","#aaa"]};
  const W=s||20,H=Math.round(W*0.68);
  const els=[];
  if(f.t==="Q"){
    [[0,0],[15,0],[0,10],[15,10]].forEach(([x,y],k)=>els.push(<rect key={"q"+k} x={x} y={y} width={15} height={10} fill={f.c[k]}/>));
  } else {
    const ws=f.w||f.c.map(()=>1), tot=ws.reduce((a,b)=>a+b,0);
    let acc=0;
    f.c.forEach((col,k)=>{
      const fr=ws[k]/tot;
      if(f.t==="V")els.push(<rect key={"b"+k} x={30*acc-0.1} y={0} width={30*fr+0.2} height={20} fill={col}/>);
      else els.push(<rect key={"b"+k} x={0} y={20*acc-0.1} width={30} height={20*fr+0.2} fill={col}/>);
      acc+=fr;
    });
  }
  (f.o||[]).forEach((o,k)=>{
    const tp=o[0],c=o[1];
    if(tp==="ci")els.push(<circle key={"o"+k} cx={o[2]} cy={o[4]!==undefined?o[4]:10} r={o[3]} fill={c}/>);
    else if(tp==="st"){const cx=o[2],sz=o[3],cy=o[4]!==undefined?o[4]:10;
      els.push(<text key={"o"+k} x={cx} y={cy+sz*0.36} textAnchor="middle" fontSize={sz} fill={c}>{"\u2605"}</text>);}
    else if(tp==="cr")els.push(<g key={"o"+k}><circle cx={o[3]} cy={o[4]} r={o[5]} fill={c}/><circle cx={o[3]+o[5]*0.5} cy={o[4]} r={o[5]*0.85} fill={o[2]}/></g>);
    else if(tp==="pc")els.push(<g key={"o"+k}><rect x={12.6} y={4} width={4.8} height={12} fill={c}/><rect x={9} y={7.6} width={12} height={4.8} fill={c}/></g>);
    else if(tp==="fc")els.push(<g key={"o"+k}><rect x={12.8} y={0} width={4.4} height={20} fill={c}/><rect x={0} y={7.8} width={30} height={4.4} fill={c}/></g>);
    else if(tp==="nc")els.push(<g key={"o"+k}><rect x={8.5} y={0} width={5.2} height={20} fill={c}/><rect x={0} y={7.4} width={30} height={5.2} fill={c}/>{o[2]?<g><rect x={9.8} y={0} width={2.6} height={20} fill={o[2]}/><rect x={0} y={8.7} width={30} height={2.6} fill={o[2]}/></g>:null}</g>);
    else if(tp==="sa")els.push(<g key={"o"+k} stroke={c} strokeWidth={4}><line x1={0} y1={0} x2={30} y2={20}/><line x1={30} y1={0} x2={0} y2={20}/></g>);
    else if(tp==="tr")els.push(<polygon key={"o"+k} points={"0,0 "+o[2]+",10 0,20"} fill={c}/>);
    else if(tp==="ca")els.push(<rect key={"o"+k} x={0} y={0} width={13} height={10.5} fill={c}/>);
    else if(tp==="dm")els.push(<polygon key={"o"+k} points="15,2.5 26.5,10 15,17.5 3.5,10" fill={c}/>);
    else if(tp==="rc")els.push(<rect key={"o"+k} x={o[2]} y={o[3]} width={o[4]} height={o[5]} fill={c}/>);
    else if(tp==="pg")els.push(<polygon key={"o"+k} points={o[2]} fill={c}/>);
    else if(tp==="ck"){const sq=[];for(let r=0;r<2;r++)for(let q=0;q<3;q++)if((r+q)%2===0)sq.push(<rect key={r+"_"+q} x={12+q*2} y={7+r*2} width={2} height={2} fill={c}/>);else sq.push(<rect key={r+"_"+q} x={12+q*2} y={7+r*2} width={2} height={2} fill="#fff"/>);
      els.push(<g key={"o"+k}>{sq}</g>);}
    else if(tp==="hc")els.push(<path key={"o"+k} d={"M "+(o[2]-o[3])+" 10 a "+o[3]+" "+o[3]+" 0 0 0 "+(o[3]*2)+" 0 z"} fill={c}/>);
    else if(tp==="ul"){
      // emblema Ulster: estrella blanca 6 puntas, mano roja al centro, corona arriba
      els.push(<circle key={"o"+k+"c"} cx={15} cy={10} r={4.8} fill="#fff" stroke="#c8102e" strokeWidth={0.4}/>);
      const sp=[];for(let a=0;a<6;a++){const ang=a*Math.PI/3-Math.PI/2;sp.push((15+Math.cos(ang)*4.6)+","+(10+Math.sin(ang)*4.6));sp.push((15+Math.cos(ang+Math.PI/6)*2.4)+","+(10+Math.sin(ang+Math.PI/6)*2.4));}
      els.push(<polygon key={"o"+k+"s"} points={sp.join(" ")} fill="#fff" stroke="#c8102e" strokeWidth={0.3}/>);
      els.push(<rect key={"o"+k+"cr"} x={13.4} y={4.6} width={3.2} height={1.6} fill="#f6b40e" stroke="#c8102e" strokeWidth={0.2}/>);
      els.push(<path key={"o"+k+"h"} d="M13.4 11.6 h3.2 v-2.4 l-0.5 0.6 v-1.2 l-0.5 0.4 v-1.2 l-0.6 0.5 v-1.1 l-0.6 0.4 v1.6 l-1 0.9 z" fill="#c8102e"/>);
    }
    else if(tp==="hs"){els.push(<g key={"o"+k} fill={c}><path d="M5.5 4.5 q3 0.4 3.3 3.2 l-1.1 0 q-0.3 -1.9 -2.2 -2.1 z"/><rect x={5.6} y={3.2} width={0.9} height={5.2} transform="rotate(-32 6 6)"/><rect x={4.2} y={3.6} width={3.6} height={0.9} transform="rotate(52 6 4)"/></g>);els.push(<polygon key={"o"+k+"st"} points="6,2.2 6.4,3 7.3,3 6.6,3.6 6.9,4.4 6,3.9 5.1,4.4 5.4,3.6 4.7,3 5.6,3" fill={c}/>);}
  });
  return <svg viewBox="0 0 30 20" width={W} height={H} style={{verticalAlign:"-2px",border:"1px solid "+C.line2,background:"#fff"}}>{els}</svg>;
}
